import React, { useState, useEffect } from 'react';
import { parkingSpotAPI } from '../services/api';

const ParkingSpotsList = () => {
  const [spots, setSpots] = useState([]);
  const [filters, setFilters] = useState({ city: '', spotType: '', priceMax: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchSpots();
  }, []);

  const fetchSpots = async (searchFilters = {}) => {
    setLoading(true);
    try {
      const response = await parkingSpotAPI.getAllSpots(searchFilters);
      setSpots(response.data.data);
    } catch (error) {
      console.error('Failed to fetch spots:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters({ ...filters, [name]: value });
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchSpots(filters);
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2>Available Parking Spots</h2>

      <form onSubmit={handleSearch} style={{ marginBottom: '20px' }}>
        <div style={{ display: 'flex', gap: '10px' }}>
          <input
            type="text"
            name="city"
            placeholder="City"
            value={filters.city}
            onChange={handleFilterChange}
            style={{ padding: '8px' }}
          />
          <select
            name="spotType"
            value={filters.spotType}
            onChange={handleFilterChange}
            style={{ padding: '8px' }}
          >
            <option value="">All Types</option>
            <option value="covered">Covered</option>
            <option value="open">Open</option>
            <option value="garage">Garage</option>
          </select>
          <input
            type="number"
            name="priceMax"
            placeholder="Max Price"
            value={filters.priceMax}
            onChange={handleFilterChange}
            style={{ padding: '8px' }}
          />
          <button type="submit" style={{ padding: '8px 20px', cursor: 'pointer' }}>
            Search
          </button>
        </div>
      </form>

      {loading ? (
        <p>Loading...</p>
      ) : (
        <div>
          {spots.length === 0 ? (
            <p>No parking spots found</p>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' }}>
              {spots.map((spot) => (
                <div key={spot._id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '5px' }}>
                  <h3>{spot.location.address}</h3>
                  <p><strong>City:</strong> {spot.location.city}</p>
                  <p><strong>Type:</strong> {spot.spotType}</p>
                  <p><strong>Price/Hour:</strong> ${spot.pricePerHour}</p>
                  <p><strong>Rating:</strong> {spot.rating} ⭐</p>
                  <button style={{ padding: '8px 15px', cursor: 'pointer' }}>
                    View Details
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ParkingSpotsList;
